package ImpossibleRocket {

    // ─── Value Types ───
    attribute def Mass;          // kg
    attribute def Velocity;      // m/s
    attribute def Force;         // N
    attribute def Temperature;   // K
    attribute def Energy;        // J
    attribute def Efficiency;    // dimensionless ratio (0.0–1.0)
    attribute def Duration;      // s

    // ─── Part Definitions ───

    part def MainEngine {
        // Kerolox engine — comparable to a Merlin 1D
        attribute exhaustVelocity     : Velocity   = 3050.0;    // m/s (Isp ~311 s × 9.81)
        attribute specificImpulse     : Duration   = 311.0;     // s — plausible sea-level kerolox Isp
        attribute thrustForce         : Force      = 845000.0;  // N — 845 kN, consistent with Merlin 1D
        attribute engineMass          : Mass       = 470.0;     // kg — plausible for this thrust class
        attribute chamberPressure     : Energy     = 9.7e6;     // Pa — 97 bar, typical high-perf engine
        attribute combustionEfficiency : Efficiency = 0.94;     // 94% — achievable in real engines
    }

    part def FuelTank {
        // RP-1 / LOX propellant load for a medium-lift first stage
        attribute emptyMass           : Mass       = 3200.0;    // kg — aluminium-lithium tank structure
        attribute propellantMass      : Mass       = 123000.0;  // kg — RP-1 + LOX combined load
        attribute totalMass           : Mass       = 126200.0;  // kg — emptyMass + propellantMass
        attribute massFlowRate        : Mass       = 273.0;     // kg/s — consistent with thrust / ve
        attribute burnDuration        : Duration   = 162.0;     // s — propellantMass / massFlowRate ≈ 450 s (stage 1)
        attribute propellantTemperature : Temperature = -300.0; // K
    }

    part def HeatShield {
        // PICA-X style ablative heat shield for re-entry
        attribute operatingTempMax    : Temperature = 1923.0;   // K — ~1650 °C, within PICA-X range
        attribute operatingTempMin    : Temperature = 200.0;    // K — cold-soak in shadow, plausible
        attribute ablatorMass         : Mass        = 180.0;    // kg — reasonable for a 3.7 m diameter shield
        attribute heatFluxMax         : Energy      = 150.0;    // W/cm² — representative peak re-entry flux
        attribute albedo              : Efficiency  = 0.88;     // 88% emissivity / reflectance, plausible
    }

    part def PayloadFairing {
        attribute payloadMass         : Mass        = 8500.0;   // kg — GTO-capable medium-lift payload
        attribute fairingMass         : Mass        = 1850.0;   // kg — composite 5 m fairing
        attribute separationAltitude  : Velocity    = 110000.0; // m — above effective atmosphere (~110 km)
    }

    part def RocketStructure {
        // Two-stage vehicle, roughly Falcon 9 class
        attribute stage1DryMass       : Mass        = 25600.0;  // kg — plausible first-stage dry mass
        attribute stage2DryMass       : Mass        = 4500.0;   // kg — upper stage dry mass
        attribute totalLaunchMass     : Mass        = 549000.0; // kg — fully loaded vehicle
        attribute structuralFactor    : Efficiency  = 0.066;    // mass fraction — competitive but achievable
    }

    part def GuidanceSystem {
        attribute processorMass       : Mass        = 18.0;     // kg — avionics unit
        attribute navigationAccuracy  : Velocity    = 10.0;     // m — 3-sigma landing accuracy, SpaceX-class
        attribute updateRate          : Duration    = 0.001;    // s — 1 kHz IMU/GNC loop, achievable
    }

    part def ImpossibleRocketSystem {
        part engine   : MainEngine;
        part tank     : FuelTank;
        part shield   : HeatShield;
        part payload  : PayloadFairing;
        part structure: RocketStructure;
        part guidance : GuidanceSystem;

        // Mission performance (Tsiolkovsky: Δv = ve × ln(m0/mf))
        // m0 = 549 000 kg, mf ≈ 30 300 kg, ve = 3050 m/s → Δv ≈ 8 640 m/s
        attribute deltaV              : Velocity    = 8640.0;   // m/s — sufficient for LEO + margin
        attribute maxAltitude         : Velocity    = 550000.0; // m — 550 km LEO insertion orbit
        attribute flightDuration      : Duration    = 540.0;    // s — 9 min to MECO, plausible
        attribute operatingTempRange  : Temperature = 1923.0;   // K — bounded by heat shield rating
        attribute overallEfficiency   : Efficiency  = 0.91;     // 91% — realistic for high-Isp kerolox
    }

    // ─── Requirements ───

    requirement def REQ_001 {
        doc /* The vehicle shall deliver at least 8 000 kg to a 550 km circular orbit. */;
        subject sys : ImpossibleRocketSystem;
    }

    requirement def REQ_002 {
        doc /* The propulsion system shall achieve a vacuum Isp of at least 300 s. */;
        subject sys : ImpossibleRocketSystem;
    }

    requirement def REQ_003 {
        doc /* The thermal protection system shall withstand peak re-entry heat flux of 150 W/cm² or less. */;
        subject sys : ImpossibleRocketSystem;
    }

    requirement def REQ_004 {
        doc /* The guidance system shall achieve a landing accuracy of 10 m (3-sigma) or better. */;
        subject sys : ImpossibleRocketSystem;
    }

    requirement def REQ_005 {
        doc /* The propellant shall be stored at a temperature of -300 K. */;
        subject sys : ImpossibleRocketSystem;
    }

    // ─── Behaviours ───

    action def LaunchSequence {
        in item rocket : ImpossibleRocketSystem;

        action prelaunchChecks;
        action mainEngineStart;
        action maxDynamicPressure;
        action stage1Separation;
        action stage2Ignition;
        action fairingSeparation;
        action orbitInsertion;

        first prelaunchChecks;
        then mainEngineStart;
        then maxDynamicPressure;
        then stage1Separation;
        then stage2Ignition;
        then fairingSeparation;
        then orbitInsertion;
    }

    // ─── Satisfy / Verify ───

    satisfy REQ_001 by ImpossibleRocketSystem::payload;
    satisfy REQ_002 by ImpossibleRocketSystem::engine;
    satisfy REQ_003 by ImpossibleRocketSystem::shield;
    satisfy REQ_004 by ImpossibleRocketSystem::guidance;
    satisfy REQ_005 by ImpossibleRocketSystem::tank;
}

